import React, { useState, useEffect } from 'react';
import API from '../services/api';
import './AdminAnalytics.css';

function AdminAnalytics() {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [period, setPeriod] = useState('week');

  // Данные с бэкенда
  const [dashboard, setDashboard] = useState(null);
  const [popularListings, setPopularListings] = useState([]);
  const [searchQueries, setSearchQueries] = useState([]);
  const [priceStats, setPriceStats] = useState(null);
  const [viewsStats, setViewsStats] = useState(null);

  useEffect(() => {
    loadAllAnalytics();
  }, [period]);

  const loadAllAnalytics = async () => {
    setLoading(true);
    setError(null);

    try {
      // Загружаем все эндпоинты
      const [dashboardData, popularData, searchData, priceData] = await Promise.all([
        API.get('/analytics/analytics/dashboard?days=30'),
        API.get(`/analytics/analytics/listings/popular?period=${period}&limit=10`),
        API.get('/analytics/analytics/search/queries?days=7'),
        API.get('/analytics/analytics/prices')
      ]);

      setDashboard(dashboardData.data);
      setPopularListings(popularData.data);
      setSearchQueries(searchData.data.popular_queries || []);
      setPriceStats(priceData.data);

      // Подсчет просмотров из данных популярных объявлений
      const totalViews = popularData.data.reduce((sum, item) => sum + (item.views || 0), 0);
      const avgViews = popularData.data.length > 0
        ? Math.round(totalViews / popularData.data.length)
        : 0;

      setViewsStats({
        total: totalViews,
        average: avgViews,
        period: period,
        listingsCount: popularData.data.length
      });

    } catch (err) {
      console.error('Ошибка загрузки аналитики:', err);
      setError('Не удалось загрузить данные аналитики');
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="loader">📊 Загрузка аналитики...</div>;
  if (error) return <div className="error">❌ {error}</div>;

  return (
    <div className="analytics-page">
      <h1>📊 Аналитика</h1>

      {/* Кнопки периода */}
      <div className="period-selector">
        <button
          className={period === 'day' ? 'active' : ''}
          onClick={() => setPeriod('day')}
        >
          День
        </button>
        <button
          className={period === 'week' ? 'active' : ''}
          onClick={() => setPeriod('week')}
        >
          Неделя
        </button>
        <button
          className={period === 'month' ? 'active' : ''}
          onClick={() => setPeriod('month')}
        >
          Месяц
        </button>
      </div>

      {/* Dashboard метрики */}
      {dashboard && (
        <div className="metrics-grid">
          <div className="metric-card">
            <h3>Всего объявлений</h3>
            <p className="metric-value">{dashboard.total_listings || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Активных сегодня</h3>
            <p className="metric-value">{dashboard.active_today || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Просмотров сегодня</h3>
            <p className="metric-value">{dashboard.views_today || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Новых сегодня</h3>
            <p className="metric-value">{dashboard.new_listings_today || 0}</p>
          </div>
        </div>
      )}

      {/* Статистика просмотров */}
      {viewsStats && (
        <div className="analytics-card">
          <h2>👁 Статистика просмотров за {period}</h2>
          <div className="stats-grid">
            <div className="stat-item">
              <span className="stat-label">Всего просмотров (топ-10):</span>
              <span className="stat-value">{viewsStats.total.toLocaleString()}</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">В среднем на объявление:</span>
              <span className="stat-value">{viewsStats.average.toLocaleString()}</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Учитывается объявлений:</span>
              <span className="stat-value">{viewsStats.listingsCount}</span>
            </div>
          </div>
        </div>
      )}

      {/* Детальная статистика цен */}
      {priceStats && (
        <div className="analytics-card">
          <h2>💰 Детальная статистика цен</h2>

          {/* Общая статистика */}
          <div className="stats-grid">
            <div className="stat-item highlight">
              <span className="stat-label">Всего активных объявлений:</span>
              <span className="stat-value large">{priceStats.total_active || 0}</span>
            </div>
            <div className="stat-item highlight">
              <span className="stat-label">Средняя цена:</span>
              <span className="stat-value large">{(priceStats.avg_price || 0).toLocaleString()} ₽</span>
            </div>
            <div className="stat-item highlight">
              <span className="stat-label">Средняя цена за м²:</span>
              <span className="stat-value large">{(priceStats.avg_price_per_m2 || 0).toLocaleString()} ₽</span>
            </div>
          </div>

          {/* Статистика по типам недвижимости */}
          {priceStats.by_type && priceStats.by_type.length > 0 && (
            <>
              <h3>📊 По типам недвижимости</h3>
              <table className="stats-table">
                <thead>
                  <tr>
                    <th>Тип недвижимости</th>
                    <th>Количество</th>
                    <th>Средняя цена</th>
                    <th>Цена за м²</th>
                    <th>Доля рынка</th>
                  </tr>
                </thead>
                <tbody>
                  {priceStats.by_type.map((item, idx) => {
                    const share = ((item.count / priceStats.total_active) * 100).toFixed(1);
                    return (
                      <tr key={idx}>
                        <td><strong>{item.type || 'Другое'}</strong></td>
                        <td>{item.count || 0}</td>
                        <td>{(item.avg_price || 0).toLocaleString()} ₽</td>
                        <td>{(item.avg_price_per_m2 || 0).toLocaleString()} ₽</td>
                        <td>{share}%</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </>
          )}

          {/* Дополнительная статистика если есть */}
          {priceStats.summary && (
            <div className="stats-mini-grid">
              <div className="stat-mini-item">
                <span className="stat-mini-label">Минимальная цена:</span>
                <span className="stat-mini-value">{(priceStats.summary.min_price || 0).toLocaleString()} ₽</span>
              </div>
              <div className="stat-mini-item">
                <span className="stat-mini-label">Максимальная цена:</span>
                <span className="stat-mini-value">{(priceStats.summary.max_price || 0).toLocaleString()} ₽</span>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Две колонки */}
      <div className="analytics-columns">
        {/* Популярные объявления */}
        <div className="analytics-card">
          <h2>🔥 Популярные за {period}</h2>
          <div className="listings-list">
            {popularListings.length > 0 ? (
              popularListings.map((item, index) => (
                <div key={item.listing_id || index} className="listing-item">
                  <span className="rank">{index + 1}</span>
                  <div className="listing-info">
                    <h4>{item.title || 'Без названия'}</h4>
                    <p>{item.address || 'Адрес не указан'}</p>
                  </div>
                  <div className="listing-stats">
                    <span className="views">👁 {item.views || 0}</span>
                    <span className="price">
                      {item.price ? item.price.toLocaleString() : 0} ₽
                    </span>
                  </div>
                </div>
              ))
            ) : (
              <p className="no-data">Нет данных за период</p>
            )}
          </div>
        </div>

        {/* Популярные поисковые запросы */}
        <div className="analytics-card">
          <h2>🔍 Популярные запросы</h2>
          <div className="queries-list">
            {searchQueries.length > 0 ? (
              searchQueries.map((item, index) => (
                <div key={index} className="query-item">
                  <span className="rank">{index + 1}</span>
                  <span className="query">"{item.query || 'пустой запрос'}"</span>
                  <span className="count">{item.count || 0} раз</span>
                </div>
              ))
            ) : (
              <p className="no-data">Нет данных о поиске</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default AdminAnalytics;
